import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        if (input.length() > bufferSize) {
            System.out.println("Input string exceeds buffer size. Truncating...");
            input.getChars(0, bufferSize, buffer, 0);
        } else {
            input.getChars(0, input.length(), buffer, 0);
        }

        System.out.println("Buffer contents: " + new String(buffer));

        // No buffer overflow vulnerability as we ensure input length does not exceed buffer size
    }
}

### Explanation:
취약유형: Buffer Overflow
